Here are the public test cases for feature1_client_identification:
{
  "description": "An authorization request is rejected before any redirect can occur when the client cannot be identified. Submitting a request with no client identifier, or with an identifier that is not registered, yields a direct (non-redirect) error response carrying an HTTP client-error status and a stable error code distinguishing the two situations by description.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {}
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=invalid_client\nbody.error_description=No client id supplied\n"
    },
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {
              "client_id": "Fake Client ID"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=invalid_client\nbody.error_description=The client id supplied is invalid\n"
    }
  ]
}

Here are the public test cases for feature2_1_no_redirect_uri:
{
  "description": "When a request names a registered client that has no stored redirect target and supplies none in the request, the endpoint cannot safely redirect and returns a direct error response with a client-error status and an invalid-URI error code.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {
              "client_id": "Test Client ID"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=invalid_uri\nbody.error_description=No redirect URI was supplied or stored\n"
    }
  ]
}

Here are the public test cases for feature2_2_fragment_rejected:
{
  "description": "A supplied redirect target that contains a URL fragment component is rejected with a direct error response (client-error status, invalid-URI error code), because authorization parameters may not be appended to a fragment.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com#fragment",
              "response_type": "code"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=invalid_uri\nbody.error_description=The redirect URI must not contain a fragment\n"
    }
  ]
}

Here are the public test cases for feature2_3_mismatch:
{
  "description": "When a client has exactly one registered redirect target and the request supplies a different one, the request is rejected with a direct error response carrying a client-error status, a mismatch error code, and a reference link to the relevant specification section.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID with Redirect Uri",
              "redirect_uri": "http://adobe.com",
              "response_type": "code"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=redirect_uri_mismatch\nbody.error_description=The redirect URI provided is missing or does not match\nbody.error_uri=http://tools.ietf.org/html/rfc6749#section-3.1.2\n"
    }
  ]
}

Here are the public test cases for feature2_4_multiple_requires_selection:
{
  "description": "When a client registers more than one redirect target and the request omits the redirect parameter, the endpoint cannot choose one automatically and returns a direct error response (client-error status, invalid-URI error code, spec reference) requiring the caller to specify which registered target to use.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID with Multiple Redirect Uris",
              "response_type": "code"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=invalid_uri\nbody.error_description=A redirect URI must be supplied when multiple redirect URIs are registered\nbody.error_uri=http://tools.ietf.org/html/rfc6749#section-3.1.2.3\n"
    }
  ]
}

Here are the public test cases for feature2_5_exact_match_required:
{
  "description": "Under a strict exact-match policy, a supplied redirect target whose query string differs from the registered one (even if the scheme/host/path match) is rejected with a direct mismatch error response and a spec reference.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID with Redirect Uri Parts",
              "response_type": "code",
              "redirect_uri": "http://user:pass@brentertainment.com:2222/authorize/cb?auth_type=oauth&test=true&hereisa=querystring"
            }
          }
        ],
        "config": {
          "require_exact_redirect_uri": true
        }
      },
      "expected_output": "response=0\nstatus=400\ntype=response\nbody.error=redirect_uri_mismatch\nbody.error_description=The redirect URI provided is missing or does not match\nbody.error_uri=http://tools.ietf.org/html/rfc6749#section-3.1.2\n"
    }
  ]
}

Here are the public test cases for feature3_response_type:
{
  "description": "Once the client and redirect target are valid, a request that omits the response-type selector, or supplies an unrecognized one, is reported by REDIRECTING the user agent back to the validated redirect target with an error code and description encoded in the query string, rather than as a direct error body.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=adobe.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.error=invalid_request\nquery.error_description=Invalid or missing response type\n"
    },
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com",
              "response_type": "invalid"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=adobe.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.error=invalid_request\nquery.error_description=Invalid or missing response type\n"
    }
  ]
}

