Here are the public test cases for feature5_scope_enforcement:
{
  "description": "When the deployment defines a set of supported scopes and no default scope, a grant-code request that omits the scope parameter is redirected back with a scope error, while the same request that names a supported scope succeeds with a redirect carrying a freshly issued grant code.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com",
              "response_type": "code",
              "state": "xyz"
            }
          }
        ],
        "scope_util": {
          "default_scope": false,
          "supported_scopes": [
            "testscope"
          ]
        }
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=adobe.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.error=invalid_scope\nquery.error_description=This application requires you specify a scope parameter\nquery.state=xyz\n"
    },
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com",
              "response_type": "code",
              "state": "xyz",
              "scope": "testscope"
            }
          }
        ],
        "scope_util": {
          "default_scope": false,
          "supported_scopes": [
            "testscope"
          ]
        }
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=adobe.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.code=CODE\nquery.state=xyz\nissued.identity_token=absent\n"
    }
  ]
}

Here are the public test cases for feature6_1_redirect_reconstruction:
{
  "description": "On success the endpoint reconstructs the redirect target faithfully, preserving every component of the supplied absolute URL (userinfo, host, port, path, and pre-existing query parameters) while appending the issued grant code and echoing the state value.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID with Redirect Uri Parts",
              "response_type": "code",
              "redirect_uri": "http://user:pass@brentertainment.com:2222/authorize/cb?auth_type=oauth&test=true",
              "state": "xyz"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=user\nredirect.host=brentertainment.com\nredirect.port=2222\nredirect.path=/authorize/cb\nredirect.fragment=\nquery.auth_type=oauth\nquery.code=CODE\nquery.state=xyz\nquery.test=true\nissued.identity_token=absent\n"
    }
  ]
}

