      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": false,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com",
              "response_type": "code",
              "state": "xyz"
            }
          }
        ]
