Here are the public test cases for feature8_code_redeemable_at_token_endpoint:
{
  "description": "A grant code issued for a client that relies on its single registered redirect target (omitting the redirect parameter in the authorization step) can subsequently be redeemed at the token endpoint WITHOUT re-supplying a redirect target; the redemption returns a success status and a token payload. The second step references the code issued by the first step.",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID with Redirect Uri",
              "response_type": "code",
              "state": "xyz"
            }
          },
          {
            "action": "token",
            "request": {
              "client_id": "Test Client ID with Redirect Uri",
              "client_secret": "TestSecret2",
              "grant_type": "authorization_code",
              "code": "@AUTH_CODE@"
            }
          }
        ]
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=brentertainment.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.code=CODE\nquery.state=xyz\nissued.identity_token=absent\n\nresponse=1\nstatus=200\ntype=response\nbody.access_token=ACCESS_TOKEN\nbody.expires_in=3600\nbody.refresh_token=REFRESH_TOKEN\nbody.scope=\nbody.token_type=Bearer\n"
    }
  ]
}

Here are the public test cases for feature9_identity_token_binding:
{
  "description": "When the deployment enables identity-connect features and the request asks for the identity scope, a successful grant-code authorization additionally binds an identity assertion to the issued code, observable as the code carrying an attached identity token (in contrast to the default flow, where none is attached).",
  "cases": [
    {
      "input": {
        "steps": [
          {
            "action": "authorize",
            "is_authorized": true,
            "request": {
              "client_id": "Test Client ID",
              "redirect_uri": "http://adobe.com",
              "response_type": "code",
              "state": "xyz",
              "scope": "openid"
            }
          }
        ],
        "config": {
          "use_openid_connect": true,
          "issuer": "bojanz"
        }
      },
      "expected_output": "response=0\nstatus=302\ntype=redirect\nredirect.scheme=http\nredirect.user=\nredirect.host=adobe.com\nredirect.port=\nredirect.path=\nredirect.fragment=\nquery.code=CODE\nquery.state=xyz\nissued.identity_token=present\n"
    }
  ]
}
